CREATE OR REPLACE FUNCTION public.add_subcontract_growth_exclusion(p_tender_id uuid, p_detail_cost_category_id uuid, p_exclusion_type text DEFAULT 'works'::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_id uuid;
BEGIN
  IF p_exclusion_type NOT IN ('works', 'materials') THEN
    RAISE EXCEPTION 'Invalid exclusion_type: must be ''works'' or ''materials''';
  END IF;
  INSERT INTO public.subcontract_growth_exclusions (tender_id, detail_cost_category_id, exclusion_type)
  VALUES (p_tender_id, p_detail_cost_category_id, p_exclusion_type)
  ON CONFLICT (tender_id, detail_cost_category_id, exclusion_type)
  DO UPDATE SET updated_at = now()
  RETURNING id INTO v_id;
  RETURN v_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.auto_archive_tender_registry()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE status_name TEXT;
BEGIN
  SELECT name INTO status_name FROM tender_statuses WHERE id = NEW.status_id;
  IF status_name IN ('Проиграли', 'Выиграли') THEN NEW.is_archived = TRUE;
  ELSIF status_name IN ('В работе', 'Ожидаем тендерный пакет') THEN NEW.is_archived = FALSE;
  END IF;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.auto_create_tender_registry()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  default_status_id UUID;
  next_sort_order INTEGER;
BEGIN
  SELECT id INTO default_status_id FROM tender_statuses WHERE name = 'В работе' LIMIT 1;
  IF default_status_id IS NULL THEN SELECT id INTO default_status_id FROM tender_statuses LIMIT 1; END IF;
  SELECT COALESCE(MAX(sort_order), 0) + 1 INTO next_sort_order FROM tender_registry;
  INSERT INTO tender_registry (title, client_name, tender_number, area, construction_scope_id, status_id, created_by, is_archived, sort_order)
  VALUES (NEW.title, NEW.client_name, NEW.tender_number, NEW.area_sp,
    (SELECT id FROM construction_scopes WHERE name::text = NEW.construction_scope::text LIMIT 1),
    default_status_id, NEW.created_by, FALSE, next_sort_order);
  RETURN NEW;
END;
$function$
